import{_ as e,o as i,c as o,a2 as r}from"./chunks/framework.DIMps2S2.js";const u=JSON.parse('{"title":"如何应对追加保证金通知","description":"","frontmatter":{"layout":"doc","sidebar":true},"headers":[],"relativePath":"margin/how-to-respond-to-margin-call.md","filePath":"zh-CN/margin/how-to-respond-to-margin-call.md"}'),t={name:"margin/how-to-respond-to-margin-call.md"};function l(n,a,s,h,p,d){return i(),o("div",null,[...a[0]||(a[0]=[r('<h1 id="如何应对追加保证金通知" tabindex="-1">如何应对追加保证金通知 <a class="header-anchor" href="#如何应对追加保证金通知" aria-label="Permalink to &quot;如何应对追加保证金通知&quot;">​</a></h1><p>本指南说明在收到追缴保证金通知后，如何在截止时间前补足缺口、避免账户被强制平仓。</p><hr><h2 id="第一步-确认通知内容" tabindex="-1">第一步：确认通知内容 <a class="header-anchor" href="#第一步-确认通知内容" aria-label="Permalink to &quot;第一步：确认通知内容&quot;">​</a></h2><p>打开长桥 App，进入「资产」→「融资状态」，查看以下信息：</p><ul><li><strong>应追缴保证金金额</strong>：需要补足的具体数值</li><li><strong>截止时间</strong>：通常为收到通知后第 3 个交易日（含当日）的 <strong>14:00</strong></li></ul><blockquote><p>强制平仓可在截止时间前随时执行，不会提前通知。请尽快处理，不要等到最后时刻。</p></blockquote><hr><h2 id="第二步-选择处理方式" tabindex="-1">第二步：选择处理方式 <a class="header-anchor" href="#第二步-选择处理方式" aria-label="Permalink to &quot;第二步：选择处理方式&quot;">​</a></h2><p>根据当前情况选择其中一种方式，或两种方式结合使用：</p><h3 id="方式一-存入现金" tabindex="-1">方式一：存入现金 <a class="header-anchor" href="#方式一-存入现金" aria-label="Permalink to &quot;方式一：存入现金&quot;">​</a></h3><p>适合手头有闲置资金的情况。</p><ol><li>进入「资产」→「存入资金」</li><li>选择最快到账的入金方式（如银证转账或 FPS，通常即时到账）</li><li>存入金额 ≥ 应追缴保证金金额</li><li>入金完成后返回「融资状态」确认账户恢复至安全或中等状态</li></ol><p>参考：<a href="/wiki/deposit/methods-overview">入金方式一览</a></p><h3 id="方式二-卖出持仓" tabindex="-1">方式二：卖出持仓 <a class="header-anchor" href="#方式二-卖出持仓" aria-label="Permalink to &quot;方式二：卖出持仓&quot;">​</a></h3><p>适合不想追加资金、希望降低仓位的情况。</p><ol><li>进入「资产」→ 选择要卖出的持仓</li><li>参考计算所需卖出市值（见下方说明）</li><li>以市价或限价委托卖出</li><li>成交后返回「融资状态」确认账户状态</li></ol><p><strong>所需卖出市值估算：</strong></p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>所需卖出市值 ≤ (初始保证金要求 - 股权资产) ÷ 该持仓 IM 系数</span></span></code></pre></div><p>例：初始保证金要求 $11,250，股权资产 $9,500，目标持仓 IM 系数 50%，则至少卖出 $3,500 市值。</p><hr><h2 id="第三步-确认账户恢复" tabindex="-1">第三步：确认账户恢复 <a class="header-anchor" href="#第三步-确认账户恢复" aria-label="Permalink to &quot;第三步：确认账户恢复&quot;">​</a></h2><p>处理完成后，在「资产」→「融资状态」确认风控状态已变为「安全」或「中等」。</p><p>若状态仍为「预警」或「危险」，说明补足金额不足，需继续追加或追加卖出。</p><hr><h2 id="特殊情形" tabindex="-1">特殊情形 <a class="header-anchor" href="#特殊情形" aria-label="Permalink to &quot;特殊情形&quot;">​</a></h2><p><strong>已被强制平仓</strong>：若股权资产已跌破强平保证金（FM），平台可能在不等待追缴期的情况下直接平仓。平仓后账户将自动解除危险状态，但已发生亏损无法撤销。</p><p><strong>末日期权仓位</strong>：持有到期日当天的期权时，可能跳过追缴期直接强平。若账户中有临近到期的期权，需优先处理。</p><p><strong>追缴金额高于通知差额</strong>：实际需补足金额通常高于维持保证金缺口，需补至初始保证金水平。以 App 内显示的「应追缴保证金」数值为准。</p><hr><h2 id="相关文档" tabindex="-1">相关文档 <a class="header-anchor" href="#相关文档" aria-label="Permalink to &quot;相关文档&quot;">​</a></h2><ul><li><a href="/wiki/margin/margin-requirements">保证金</a> — 三层保证金结构（IM/MM/FM）与追缴触发条件说明</li><li><a href="/wiki/margin/risk-control">账户风控</a> — 安全/中等/预警/危险四级状态定义</li><li><a href="/wiki/deposit/how-to-choose-deposit-method">如何选择入金方式</a> — 各入金方式到账速度与手续费对比</li></ul><h2 id="引用此页面的文档" tabindex="-1">引用此页面的文档 <a class="header-anchor" href="#引用此页面的文档" aria-label="Permalink to &quot;引用此页面的文档&quot;">​</a></h2><ul><li><a href="/wiki/deposit/how-to-choose-deposit-method">如何选择入金方式</a></li><li><a href="/wiki/getting-started/first-margin-buy">完成首笔融资买入</a></li><li><a href="/wiki/margin/margin-requirements">保证金</a></li></ul>',34)])])}const m=e(t,[["render",l]]);export{u as __pageData,m as default};
